<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Bouncing Ball Playground</title>
  <style>
    body {
      background: #111;
      color: white;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }
    canvas {
      border: 1px solid #444;
      background-color: #222;
      image-rendering: pixelated;
    }
    button {
      margin: 5px;
      padding: 10px 20px;
      font-size: 16px;
      cursor: pointer;
    }
  </style>
</head>
<body>
  <canvas id="sim" width="400" height="400"></canvas>
  <div>
    <button id="drop">Drop</button>
    <button id="play">Play</button>
    <button id="clear">Clear</button>
  </div>
  <script>
    const simCanvas = document.getElementById('sim');
    const ctx = simCanvas.getContext('2d');

    let balls = [];
    let running = false;
    let lastTime;

    const gravity = 0.5;
    const restitution = 0.7;

    window.sim = {
      w: simCanvas.width,
      h: simCanvas.height,
      balls() {
        return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
      },
      addBall(x, y, vx=0, vy=0, r) {
        const radius = r !== undefined ? r : 15 + Math.random() * 15;
        balls.push({
          x, y, vx, vy,
          r: radius,
          color: `hsl(${Math.floor(Math.random()*360)},70%,50%)`
        });
      },
      clear() {
        balls = [];
      },
      step(dt=1) {
        for (let ball of balls) {
          // Apply gravity
          ball.vy += gravity * dt;

          // Update position
          ball.x += ball.vx * dt;
          ball.y += ball.vy * dt;

          // Horizontal collisions
          if (ball.x - ball.r < 0) {
            ball.x = ball.r;
            ball.vx *= -restitution;
          } else if (ball.x + ball.r > this.w) {
            ball.x = this.w - ball.r;
            ball.vx *= -restitution;
          }

          // Vertical collisions
          if (ball.y - ball.r < 0) {
            ball.y = ball.r;
            ball.vy *= -restitution;
          } else if (ball.y + ball.r > this.h) {
            ball.y = this.h - ball.r;
            ball.vy *= -restitution;
          }
        }

        // Draw
        ctx.clearRect(0, 0, simCanvas.width, simCanvas.height);
        for (let ball of balls) {
          ctx.beginPath();
          ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI*2);
          ctx.fillStyle = ball.color;
          ctx.fill();
        }
      },
    };

    // Event handlers
    document.getElementById('drop').addEventListener('click', () => {
      const x = simCanvas.width / 2;
      const y = 10;
      window.sim.addBall(x, y);
    });

    document.getElementById('play').addEventListener('click', () => {
      running = !running;
      this.play.textContent = running ? 'Pause' : 'Play';
      if (running) {
        lastTime = performance.now();
        animate();
      }
    });

    document.getElementById('clear').addEventListener('click', () => {
      window.sim.clear();
    });

    simCanvas.addEventListener('click', e => {
      const rect = simCanvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      window.sim.addBall(x, y);
    });

    function animate() {
      if (!running) return;
      requestAnimationFrame(animate);
      const now = performance.now();
      const delta = (now - lastTime)/1000; // seconds
      window.sim.step(delta);
      lastTime = now;
    }

    // Initial draw
    window.sim.step(0);
  </script>
</body>
</html>
